srcDoc.css:
* {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

body {
  font-family: Inter, system-ui, sans-serif;
  background: transparent;
}

#notes-list {
  display: flex;
  flex-direction: column;
  gap: 6px;
  margin-bottom: 12px;
  max-height: 280px;
  overflow-y: auto;
}

.note {
  background: #F9FAFB;
  border-radius: 6px;
  padding: 9px 12px;
  border-left: 3px solid #E5E7EB;
}

.note-meta {
  font-size: 10px;
  color: #9CA3AF;
  margin-bottom: 3px;
  display: flex;
  align-items: center;
  gap: 6px;
}

.note-author {
  color: #1A5C3A;
  font-weight: 600;
}

.note-text {
  font-size: 12px;
  color: #1A1A2E;
  line-height: 1.5;
}

.empty {
  font-size: 12px;
  color: #9CA3AF;
  font-style: italic;
  padding: 8px 0;
}

.input-row {
  display: flex;
  gap: 8px;
  align-items: center;
}

input {
  flex: 1;
  font-family: inherit;
  font-size: 12px;
  color: #1A1A2E;
  background: #FFFFFF;
  border: 1.5px solid #E5E7EB;
  border-radius: 6px;
  padding: 8px 10px;
  outline: none;
  transition: border-color 0.15s;
}

input:focus {
  border-color: #1A5C3A;
  box-shadow: 0 0 0 3px rgba(26, 92, 58, 0.08);
}

input::placeholder {
  color: #9CA3AF;
}

#add-btn {
  background: #1A5C3A;
  color: #fff;
  border: none;
  border-radius: 6px;
  padding: 8px 14px;
  font-size: 12px;
  font-weight: 600;
  font-family: inherit;
  cursor: pointer;
  white-space: nowrap;
  flex-shrink: 0;
}

#add-btn:hover {
  opacity: 0.9;
}

#add-btn:disabled {
  background: #9CA3AF;
  cursor: not-allowed;
}

