appsmith.onReady(function () {
  render();
});
appsmith.onModelChange(function () {
  render();
});
function render() {
  var notes = appsmith.model.notes || [];
  var list = document.getElementById('notes-list');
  list.innerHTML = '';
  if (!notes.length) {
    list.innerHTML = '<div class="empty">No notes yet.</div>';
    return;
  }
  notes.forEach(function (n) {
    var div = document.createElement('div');
    div.className = 'note';
    div.innerHTML = '<div class="note-meta">' + '<span class="note-author">' + (n.created_by || 'System') + '</span>' + '<span>·</span>' + '<span>' + (n.created_at || '') + '</span>' + '</div>' + '<div class="note-text">' + (n.note_text || n.note || '') + '</div>';
    list.appendChild(div);
  });
  list.scrollTop = list.scrollHeight;
}
window.addNote = function () {
  var input = document.getElementById('note-input');
  var btn = document.getElementById('add-btn');
  var text = input.value.trim();
  if (!text) {
    input.style.borderColor = '#E74C3C';
    return;
  }
  input.style.borderColor = '#E5E7EB';
  btn.disabled = true;
  btn.textContent = 'Adding...';
  appsmith.updateModel({
    pendingNote: text
  });
  input.value = '';
  btn.disabled = false;
  btn.textContent = 'Add';
  appsmith.triggerEvent('onAddNote');
};

